import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    def distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    num_customers = len(unvisited_customers)
    if num_customers == 0:
        return None

    best_node = None
    min_priority_score = float('inf')

    for i, customer in enumerate(unvisited_customers):
        customer_distance = distance(cur_truck_pos, customer)
        depot_distance = distance(customer, depot_pos)
        time_to_customer = customer_distance / (customer_distance + depot_distance)
        closer_trucks_count = sum(distance(truck_pos, customer) < customer_distance for truck_pos in all_truck_pos)
        penalty = 0.5 * closer_trucks_count
        priority_score = 0.6 * time_to_customer + penalty

        if priority_score < min_priority_score:
            min_priority_score = priority_score
            best_node = i

    return best_node

import numpy as np

# {The new algorithm relies on a proactive strategy employing foresight by projecting potential future states and selecting the node that minimizes the expected waiting time for all trucks, considering future customer additions and dynamic conditions.}

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    if not unvisited_customers:
        return None

    projected_wait_times = []

    for i, customer in enumerate(unvisited_customers):
        travel_time = np.linalg.norm(cur_truck_pos - customer)
        total_wait_time = 0

        for other_truck_pos in all_truck_pos:
            if not np.array_equal(other_truck_pos, cur_truck_pos):
                projected_travel_time = np.linalg.norm(other_truck_pos - customer)
                if projected_travel_time < travel_time:
                    total_wait_time += travel_time - projected_travel_time

        projected_wait_times.append((i, total_wait_time))

    projected_wait_times.sort(key=lambda x: x[1])
    best_node = projected_wait_times[0][0]

    return best_node
